import "./AddEmployee.css";
import { useNavigate, useParams } from "react-router-dom";
import { useEffect, useState } from "react";

function AddEmployee() {
  const navigate = useNavigate();
  const { id } = useParams(); // detect edit mode

  const [employee, setEmployee] = useState({
    id: "",
    name: "",
    dob: "",
    department: "",
  });

  /* Load employee for edit */
  useEffect(() => {
    if (id) {
      const storedEmployees =
        JSON.parse(localStorage.getItem("employees")) || [];

      const existingEmployee = storedEmployees.find(
        (emp) => emp.id === id
      );

      if (existingEmployee) {
        setEmployee(existingEmployee);
      }
    }
  }, [id]);

  /* Input change handler */
  const handleChange = (e) => {
    const { name, value } = e.target;

    setEmployee({
      ...employee,
      [name]: value,
    });
  };

  /* Submit handler */
  const handleSubmit = (e) => {
    e.preventDefault();

    const storedEmployees =
      JSON.parse(localStorage.getItem("employees")) || [];

    if (id) {
      // UPDATE existing employee
      const updatedEmployees = storedEmployees.map((emp) =>
        emp.id === id ? employee : emp
      );

      localStorage.setItem(
        "employees",
        JSON.stringify(updatedEmployees)
      );
    } else {
      // ADD new employee
      const newEmployee = {
        ...employee,
        id: Date.now().toString(),
      };

      storedEmployees.push(newEmployee);

      localStorage.setItem(
        "employees",
        JSON.stringify(storedEmployees)
      );
    }

    navigate("/dashboard/employee-details");
  };

  return (
    <div className="employee-form-page">
      <h2>{id ? "Edit Employee" : "Add Employee"}</h2>

      <form className="employee-form" onSubmit={handleSubmit}>
        <input
          type="text"
          name="name"
          placeholder="Employee Name"
          value={employee.name}
          onChange={handleChange}
          required
        />

        <input
          type="date"
          name="dob"
          value={employee.dob}
          onChange={handleChange}
          required
        />

        <select
          name="department"
          value={employee.department}
          onChange={handleChange}
          required
        >
          <option value="">Select Department</option>
          <option value="HR">HR</option>
          <option value="IT">IT</option>
          <option value="Finance">Finance</option>
          <option value="Admin">Admin</option>
        </select>

        <button type="submit" className="submit-btn">
          {id ? "Update Employee" : "Add Employee"}
        </button>

        <button
          type="button"
          className="cancel-btn"
          onClick={() =>
            navigate("/dashboard/employee-details")
          }
        >
          Cancel
        </button>
      </form>
    </div>
  );
}

export default AddEmployee;
